function DERIVAR() {    
	if(Ctrl("list2arr").CountRow() == 0) {
		alert("Debe seleccionar al menos un reclamo para derivar");
		return false;
	}             
	else
		Ctrl('main').DoEvent("DERIVAR");
}
function MarkAll()
{
	Ctrl("list2arr").DelAllRow();

	for (t=0; t<Ctrl("list2").TotalRowsCount(); t++)
		Ctrl("list2arr").AddRow().SetAttr("id",Ctrl("list2").GetAttrValue(t, "id"));

	Ctrl("list2").Refresh();
}

function UnmarkAll()
{      
	Ctrl("list2arr").DelAllRow();
	Ctrl("list2").Refresh();
}


