qry:select.qry:xquery:
			for $r in sql('
	SELECT 
		QYR01_RECLAMOS.oi_reclamo, 
		QYR01_RECLAMOS.f_reclamo,
		QYR01_RECLAMOS.c_asunto,
		QYR01_RECLAMOS.n_criticidad,
		QYR01_RECLAMOS.f_vencimiento,
		QYR01_RECLAMOS.d_usuario,
		QYR01_HISTORICOS.f_reclamo as f_derivacion
	FROM 
		QYR01_RECLAMOS
		,QYR01_HISTORICOS
		{%?('##oi_oficina##'!='') 
			{%  ,QYR08_OFICINAS%} 
			{% %} 
		%}
	WHERE 					    
		QYR01_RECLAMOS.c_estado = \'Derivado\'
		AND QYR01_RECLAMOS.oi_reclamo = QYR01_HISTORICOS.oi_reclamo
		AND QYR01_RECLAMOS.n_historico = QYR01_HISTORICOS.n_historico
		{%?('##oi_oficina##'!='') 
			{%	and QYR01_HISTORICOS.oi_ofi_hasta = QYR08_OFICINAS.oi_oficina
					and QYR08_OFICINAS.oi_oficina = \'##oi_oficina##\' %} 
			{% %} 
		%}
		{%?('##c_origen##'!='') 
			{% 
				{%?('##c_origen##'='VEN') 
					{% and QYR01_RECLAMOS.f_vencimiento <= Now() %} 
					{% and QYR01_RECLAMOS.f_vencimiento <= {DateTime(#SOURCE:@valor)} %} 
				%} 
			%} 
			{% %} 
		%}
		{%?('##d_usuario##'!='') {% and QYR01_RECLAMOS.d_usuario = \'##d_usuario##\' %} {% %} %}
		{%?('##oi_modulo##'!='') {% and QYR01_RECLAMOS.oi_modulo = \'##oi_modulo##\' %} {% %} %}
		{%?('##oi_rec_origen##'!='') {% and QYR01_RECLAMOS.c_origen = \'##oi_rec_origen##\' %} {% %} %}
		{%?('##n_criticidad##'!='') {% and QYR01_RECLAMOS.n_criticidad = \'##n_criticidad##\' %} {% %} %}						
	GROUP BY 
		QYR01_RECLAMOS.oi_reclamo, 
		QYR01_RECLAMOS.f_reclamo, 
		QYR01_RECLAMOS.c_asunto, 
		QYR01_RECLAMOS.n_criticidad,
		QYR01_RECLAMOS.f_vencimiento, 
		QYR01_RECLAMOS.d_usuario,
		QYR01_HISTORICOS.f_reclamo 
	ORDER BY oi_reclamo ASC

')/ROWS/ROW
